import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import './Games.css';

const gameLibrary = [
    {
        id: 'bubble',
        name: "Zen Pop",
        description: "Pop infinite bubbles to release micro-stress. Satisfying audio and haptics included.",
        icon: "🫧",
        category: "Relaxation",
        premium: false
    },
    {
        id: 'breath',
        name: "Neural Flow",
        description: "Synchronize your breathing with a morphing geometric portal.",
        icon: "🌀",
        category: "Focus",
        premium: true
    },
    {
        id: 'match',
        name: "Memory Oasis",
        description: "Flip cards featuring calming nature scenery to improve recall.",
        icon: "🎴",
        category: "Cognitive",
        premium: true
    },
    {
        id: 'rain',
        name: "Rain Maker",
        description: "Create your own lo-fi rain soundscape by tapping different clouds.",
        icon: "🌧️",
        category: "Sleep",
        premium: true
    }
];

// --- ZEN POP GAME ---
const ZenPopGame = () => {
    const [bubbles, setBubbles] = useState([]);
    const [score, setScore] = useState(0);

    useEffect(() => {
        const interval = setInterval(() => {
            setBubbles(prev => {
                if(prev.length > 25) return prev;
                return [...prev, {
                    id: Date.now() + Math.random(),
                    x: Math.random() * 85 + 5,
                    y: Math.random() * 85 + 5,
                    size: Math.random() * 40 + 30,
                    color: ['#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#ec4899', '#06b6d4'][Math.floor(Math.random() * 6)]
                }];
            });
        }, 600);
        return () => clearInterval(interval);
    }, []);

    const popBubble = (id) => {
        setBubbles(prev => prev.filter(b => b.id !== id));
        setScore(s => s + 1);
        try {
            const audio = new Audio('https://www.soundjay.com/buttons/sounds/button-30.mp3');
            audio.volume = 0.4;
            audio.play();
        } catch(e) {}
    };

    return (
        <div style={{ width: '100%', height: '450px', position: 'relative', background: 'radial-gradient(circle at center, #1e293b, #0f172a)', borderRadius: '20px', overflow: 'hidden', border: '1px solid rgba(255,255,255,0.1)' }}>
            <div style={{ position: 'absolute', top: 20, left: 30, color: 'rgba(255,255,255,0.7)', fontSize: '28px', fontWeight: '800', zIndex: 10 }}>
                Score: <span style={{ color: '#60a5fa' }}>{score}</span>
            </div>
            <div style={{ position: 'absolute', bottom: 20, width: '100%', textAlign: 'center', color: 'rgba(255,255,255,0.3)', pointerEvents: 'none', zIndex: 1 }}>Pop the bubbles to release tension...</div>
            <AnimatePresence>
            {bubbles.map(b => (
                <motion.div 
                   key={b.id}
                   initial={{ scale: 0, opacity: 0 }}
                   animate={{ scale: 1, opacity: 1, y: [0, -20, 0] }}
                   exit={{ scale: 1.5, opacity: 0 }}
                   transition={{ duration: 0.4, y: { duration: 3, repeat: Infinity, ease: 'easeInOut' } }}
                   onClick={() => popBubble(b.id)}
                   style={{
                       position: 'absolute', left: `${b.x}%`, top: `${b.y}%`, width: `${b.size}px`, height: `${b.size}px`,
                       background: `radial-gradient(circle at 30% 30%, rgba(255,255,255,0.9), ${b.color})`,
                       borderRadius: '50%', cursor: 'pointer', boxShadow: `0 0 20px ${b.color}66`,
                       zIndex: 5
                   }}
                />
            ))}
            </AnimatePresence>
        </div>
    )
}

function GamesModal({ user, onClose, onUpgradeClick }) {
    const [activeGame, setActiveGame] = useState(null);

    const handlePlay = (game) => {
        if (game.premium && !user?.is_premium) {
            onUpgradeClick();
            return;
        }
        setActiveGame(game);
    };

    if (activeGame) {
        return (
            <div className="modal-overlay" onClick={() => setActiveGame(null)}>
                <div className="modal-content game-player-box" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '800px', padding: '30px' }}>
                    <div className="modal-header" style={{ marginBottom: '20px' }}>
                        <h2 style={{ fontSize: '28px', display: 'flex', alignItems: 'center', gap: '10px' }}>{activeGame.icon} {activeGame.name}</h2>
                        <button onClick={() => setActiveGame(null)} className="close-btn" style={{ background: 'rgba(255,255,255,0.1)', color: 'white' }}>×</button>
                    </div>

                    {activeGame.id === 'bubble' ? <ZenPopGame /> : (
                        <div className="game-viewport" style={{ height: '400px', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'linear-gradient(135deg, #1e293b, #0f172a)', borderRadius: '20px', color: 'white', flexDirection: 'column', border: '1px solid rgba(255,255,255,0.1)' }}>
                            <motion.div 
                                animate={{ rotate: 360 }} 
                                transition={{ repeat: Infinity, duration: 8, ease: "linear" }}
                                style={{ fontSize: '80px', marginBottom: '30px', filter: 'drop-shadow(0 0 20px rgba(255,255,255,0.3))' }}
                            >
                               {activeGame.icon}
                            </motion.div>
                            <h3 style={{ fontSize: '24px', marginBottom: '10px' }}>{activeGame.name} Initializing...</h3>
                            <p style={{ color: '#94a3b8', maxWidth: '300px', textAlign: 'center' }}>Connecting to premium servers to start neural synchronization.</p>
                        </div>
                    )}
                </div>
            </div>
        );
    }

    return (
        <div className="modal-overlay" onClick={onClose} style={{ zIndex: 9999 }}>
            <div className="modal-content games-modal-container" onClick={(e) => e.stopPropagation()} style={{ background: '#f8fafc', maxWidth: '900px' }}>
                <div className="modal-header">
                    <div className="games-header">
                        <h2>Arcade Oasis</h2>
                        <p>Scientifically designed mini-games to reset your nervous system.</p>
                    </div>
                    <button onClick={onClose} className="close-btn">×</button>
                </div>

                <div className="games-grid">
                    {gameLibrary.map((game) => {
                        const isLocked = game.premium && !user?.is_premium;
                        return (
                            <div key={game.id} className="game-card" onClick={() => handlePlay(game)} style={{ background: 'white', borderRadius: '24px', cursor: 'pointer', transition: 'all 0.3s' }}>
                                {isLocked && <div className="tagline" style={{ background: '#f59e0b', color: 'white', fontWeight: 'bold' }}>PREMIUM</div>}
                                <div className="game-thumbnail" style={{ background: isLocked ? '#f1f5f9' : 'linear-gradient(135deg, #e0e7ff, #f3e8ff)' }}>
                                    <span style={{ fontSize: '60px' }}>{game.icon}</span>
                                </div>
                                <div className="game-details" style={{ padding: '25px' }}>
                                    <h3 style={{ fontSize: '20px', fontWeight: '800', color: '#1e293b', marginBottom: '10px' }}>{game.name}</h3>
                                    <p style={{ color: '#64748b', fontSize: '14px', lineHeight: 1.5, marginBottom: '20px' }}>{game.description}</p>
                                    <button className={`game-btn ${isLocked ? 'locked' : ''}`} style={{ width: '100%', padding: '12px', borderRadius: '12px', border: 'none', fontWeight: '700', fontSize: '15px' }}>
                                        {isLocked ? '🔒 Unlock with Premium' : '🎮 Play Now'}
                                    </button>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
    );
}

export default GamesModal;
